class Solution {
public:
    int numberOfSpecialChars(string word) {
        int lastLower[26] = {};
        int firstUpper[26] = {};
        int res = 0;

        for (char c : word) {
            if (islower(c)) {
                lastLower[c - 'a'] = c;
            } else {
                int idx = c - 'A';
                if (firstUpper[idx] == 0) {
                    firstUpper[idx] = c;
                    if (lastLower[idx] && lastLower[idx] < firstUpper[idx]) {
                        res++;
                    }
                }
            }
        }
        return res;
    }
};
```
